debug: class Solution(object):
    def maxArea(self, height):
        """
        :type height: List[int]
        :rtype: int
        """
        max_Vol = 0
        new_Vol = 0
        for i in range(len(height)):
            for j in range(i+1,len(height)):
                if height[i] > height[j]:
                    new_Vol = (j-i)*height[j]
                elif height[i] < height[j]:
                    new_Vol = (j-i)*height[i]
                if new_Vol > max_Vol:
                    max_Vol = new_Vol
        return max_Vol
